add_action('admin_init', function () {\r
    // Redirect any user trying to access comments page\r
    global $pagenow;\r
    \r
    if ($pagenow === 'edit-comments.php') {\r
        wp_safe_redirect(admin_url());\r
        exit;\r
    }\r
\r
    // Remove comments metabox from dashboard\r
    remove_meta_box('dashboard_recent_comments', 'dashboard', 'normal');\r
\r
    // Disable support for comments and trackbacks in post types\r
    foreach (get_post_types() as $post_type) {\r
        if (post_type_supports($post_type, 'comments')) {\r
            remove_post_type_support($post_type, 'comments');\r
            remove_post_type_support($post_type, 'trackbacks');\r
        }\r
    }\r
});\r
\r
// Close comments on the front-end\r
add_filter('comments_open', '__return_false', 20, 2);\r
add_filter('pings_open', '__return_false', 20, 2);\r
\r
// Hide existing comments\r
add_filter('comments_array', '__return_empty_array', 10, 2);\r
\r
// Remove comments page in menu\r
add_action('admin_menu', function () {\r
    remove_menu_page('edit-comments.php');\r
});\r
\r
// Remove comments links from admin bar\r
add_action('init', function () {\r
    if (is_admin_bar_showing()) {\r
        remove_action('admin_bar_menu', 'wp_admin_bar_comments_menu', 60);\r
    }\r
});
